import re
_DURATION_RE = re.compile(r'([0-9]+(?:\.[0-9]+)?)(ms|s|m|h)')
_MULTIPLIERS = {'ms': .001, 's': 1., 'm': 60., 'h': 3600.}
def parse_duration(value: str) -> float:
    if not isinstance(value, str): raise ValueError('string required')
    match = _DURATION_RE.fullmatch(value)
    if match is None: raise ValueError('invalid duration')
    number, unit = match.groups()
    result = float(number) * _MULTIPLIERS[unit]
    if not math.isfinite(result): raise ValueError('finite required')
    return result
